+
+  private getCursorOrderBy(orderBy: CrudOptions['orderBy']) {
+    const order: { field: string; direction: 'asc' | 'desc' }[] = [];
+    const clauses = Array.isArray(orderBy) ? orderBy : orderBy ? [orderBy] : [];
+    for (const clause of clauses) {
+      for (const [field, value] of Object.entries(clause)) {
+        const direction = this.normalizeCursorDirection(value);
+        if (!direction) {
+          return [];
+        }
+        order.push({ field, direction });
+      }
+    }
+    const idField = this.crudConfig.id_field;
+    if (!order.some(({ field }) => field === idField)) {
+      order.push({ field: idField, direction: 'asc' });
+    }
+    return order;
+  }
+
+  private normalizeCursorDirection(value: unknown): 'asc' | 'desc' | undefined {
+    if (value === 1 || value === '1') return 'asc';
+    if (value === -1 || value === '-1') return 'desc';
+    const direction = String(value).toLowerCase();
+    return direction === 'asc' || direction === 'desc' ? direction : undefined;
+  }
+
+  private decodeCursor(cursor: string, order: { field: string; direction: string }[]) {
+    let decoded: unknown;
+    try {
+      if (!/^[A-Za-z0-9+/]*={0,2}$/.test(cursor) || cursor.length % 4 !== 0) {
+        throw new Error();
+      }
+      decoded = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('cursor must be valid Base64 JSON');
+    }
+    if (!decoded || Array.isArray(decoded) || typeof decoded !== 'object') {
+      throw new BadRequestException('cursor must be valid Base64 JSON');
+    }
+
+    const data = decoded as Record<string, unknown>;
+    const expectedSort = order
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (data.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    for (const { field } of order) {
+      if (!Object.prototype.hasOwnProperty.call(data, field)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+    return data;
+  }
+
+  private getCursorQuery(
+    cursor: Record<string, unknown>,
+    order: { field: string; direction: 'asc' | 'desc' }[],
+  ) {
+    return {
+      $or: order.map(({ field, direction }, index) => ({
+        ...Object.fromEntries(order.slice(0, index).map(({ field }) => [field, cursor[field]])),
+        [field]: { [direction === 'asc' ? '$gt' : '$lt']: cursor[field] },
+      })),
+    };
+  }
+
+  private encodeCursor(entity: T, order: { field: string; direction: string }[]) {
+    const cursor: Record<string, unknown> = {};
+    for (const { field } of order) {
+      cursor[field] = entity[field];
+    }
+    cursor.__sort = order
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
+
+  private addCursorFields(
+    opts: CrudOptions,
+    order: { field: string; direction: string }[],
+  ) {
+    if (!opts.fields || !order.length) return [];
+    const fields = opts.fields as string[];
+    const added = order.map(({ field }) => field).filter((field) => !fields.includes(field));
+    if (added.length) opts.fields = [...fields, ...added] as any;
+    return added;
+  }
+
+  private removeCursorFields(data: T[], fields: string[]) {
+    for (const entity of data || []) {
+      for (const field of fields) {
+        delete entity[field];
+      }
+    }
+  }
