const NAMES_REGEX = /([^\s,]+)/g;
const COMMENTS_REGEX = /((\/\/.*$)|(\/\*[\s\S]*?\*\/))/gm;
function getFunctionParamsNames(fun) {
  const funStr = fun.toString().replace(COMMENTS_REGEX, '');
  let res = funStr
    .slice(funStr.indexOf('(') + 1, funStr.indexOf(')'))
    .match(NAMES_REGEX);
  if (res === null) {
    res = [];
