export function parseJwtCookieFromRes(res, regex?) {
  const cookieRegex = regex || /eicrud-jwt=([^;]*);/;
  const cookie = res.headers['set-cookie'];
  for (const c of cookie || []) {
    const match = cookieRegex.exec(c);
    if (match) {
      return match;
    }
  }
}

